use std::collections::{BTreeMap, BTreeSet, HashMap};

#[derive(Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct UserAddress(pub [u8; 20]);

#[derive(Clone)]
pub struct PositionState {
    pub coin: u64,
    pub size: i128,
    pub entry_px: u128,
    pub leverage: u64,
    pub margin: u64,
    pub unrealized: i128,
    pub funding: i128,
}

#[derive(Clone)]
pub struct OrderState {
    pub oid: u64,
    pub price: u128,
    pub size: u128,
    pub side: u64,
    pub flags: u64,
    pub trigger: u128,
}

pub struct UserState {
    pub equity: u128,
    pub balance: u128,
    pub margin_used: u128,
    pub positions: BTreeMap<u64, PositionState>,
    pub orders: BTreeMap<u64, OrderState>,
}

pub struct Exchange {
    pub adl_state: HashMap<u64, u128>,
    pub default_user: UserState,
    pub users: BTreeMap<UserAddress, UserState>,
}

pub struct AdlIterEntry {
    pub discriminant: u64,
    pub asset_idx: u64,
    pub user_address: UserAddress,
    pub direction_byte: u32,
}

pub fn build_adl_candidate_set(exchange: &Exchange) -> BTreeSet<UserAddress> {
    let _ = exchange;
    let filter_users_opt: Option<Box<BTreeSet<UserAddress>>> = None;
    let iter_vec: Vec<AdlIterEntry> = Vec::new();
    let candidate_root: BTreeSet<UserAddress> = BTreeSet::new();
    let _ = iter_vec;
    let _ = filter_users_opt;
    let _ = candidate_root;
    BTreeSet::new()
}

