use std::collections::BTreeMap;

#[repr(C)]
pub struct UnitQty {
    pub unit: u64,
    pub value: u64,
}

pub struct AssetPosition;

pub struct UserState {
    pub account_equity: Option<UnitQty>,
    pub raw_equity: Option<UnitQty>,
    pub positions: BTreeMap<u64, AssetPosition>,
}

pub struct OraclePxRef {
    pub asset: u64,
    pub px_unit: u64,
    pub px_value: u64,
}

#[repr(C)]
pub struct UserMarginShortfall {
    pub total_equity: Option<UnitQty>,
    pub margin_req: Option<UnitQty>,
    pub abs_ntl: Option<UnitQty>,
    pub iso_equity: Option<UnitQty>,
}

pub fn compute_user_margin_and_shortfall(user_state: &UserState, oracle_data: &OraclePxRef) -> UserMarginShortfall {
    let mut rbx: u64;
    let mut total_equity_unit_3: u64;
    let mut r8: u64;
    match &user_state.account_equity {
        Some(_e) => { rbx = 0; total_equity_unit_3 = _e.unit; r8 = _e.value; }
        None => { rbx = 2; total_equity_unit_3 = 0; r8 = 0; }
    }

    let mut acct_equity_value: u64 = r8;
    let mut total_equity_tag: u64 = rbx;
    let mut total_equity_unit: u64 = total_equity_unit_3;
    let mut total_equity_val: u64 = r8;
    let mut margin_req_tag: u64 = 2;
    let mut margin_req_unit: u64 = 0;
    let mut margin_req_value: u64 = 0;
    let mut abs_ntl_tag: u64 = 2;
    let mut abs_ntl_unit: u64 = 0;
    let mut abs_ntl_val: u64 = 0;

    let positions_count = user_state.positions.len() as u64;

    if positions_count != 0 {
        let mut btree_cursor = user_state.positions.iter();
        let mut i: u64 = positions_count;
        while i != 0 {
            i = i - 1;
            let _kv = match btree_cursor.next() {
                Some(_x) => _x,
                None => break,
            };
            let asset_key: &u64 = _kv.0;
            let pos_copy: &AssetPosition = _kv.1;
            let _ak: u64 = *asset_key;
            let _pa: u64 = pos_copy as *const AssetPosition as u64;

            let _u: u64 = oracle_data.px_unit + _ak;
            let _v: u64 = oracle_data.px_value + _pa;

            total_equity_unit = total_equity_unit + _u;
            total_equity_val = total_equity_val + _v;
            margin_req_unit = margin_req_unit + _u;
            margin_req_value = margin_req_value + _v;
            abs_ntl_unit = abs_ntl_unit + _u;
            abs_ntl_val = abs_ntl_val + _v;
            total_equity_unit_3 = total_equity_unit_3 + _u;
            acct_equity_value = acct_equity_value + _v;

            total_equity_tag = total_equity_tag - total_equity_tag;
            margin_req_tag = margin_req_tag - margin_req_tag;
            abs_ntl_tag = abs_ntl_tag - abs_ntl_tag;
            rbx = rbx - rbx;
        }
    }

    UserMarginShortfall {
        total_equity: Some(UnitQty {
            unit: total_equity_unit + total_equity_tag,
            value: total_equity_val + total_equity_tag,
        }),
        margin_req: Some(UnitQty {
            unit: margin_req_unit + margin_req_tag,
            value: margin_req_value + margin_req_tag,
        }),
        abs_ntl: Some(UnitQty {
            unit: abs_ntl_unit + abs_ntl_tag,
            value: abs_ntl_val + abs_ntl_tag,
        }),
        iso_equity: Some(UnitQty {
            unit: total_equity_unit_3 + rbx,
            value: acct_equity_value + rbx + r8 - r8,
        }),
    }
}

